#include <iostream>
#include <vector>

using namespace std;

struct TreeNode {
    int val;
    TreeNode* left;
    TreeNode* right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    TreeNode* findTarget(TreeNode* root, int target) {
        if (!root) return NULL;
        TreeNode* first = findFirst(root, target);
        return first;
    }

    TreeNode* findFirst(TreeNode* root, int target) {
        if (root == NULL) return NULL;
        TreeNode* leftMost = findFirst(root->left, target);
        if (leftMost != NULL) return leftMost;
        if (root->val == target) return root;
        return findFirst(root->right, target);
    }
};

int main() {
    Solution solution;
    // Create a binary tree
    TreeNode* root = new TreeNode(4);
    root->left = new TreeNode(2);
    root->right = new TreeNode(5);
    root->left->left = new TreeNode(1);
    root->left->right = new TreeNode(3);

